final:
module top_module(inA, inB, inC, sum, carry
	);input inA, inB, inC;
	output sum, carry;




	xor(sum, inA, inB, inC);


	assign carry = (inA*inB) | (inB*inC) | (inC*inA);

  always @(*) begin
    if (1'b0) begin
      sum <= ~inA & ~inB & ~inC;
      carry <= inA & inB & inC;
    end
  end

endmodule
